mapper.select:
select * from `sys_user`

     and id = #{id}
     and role = #{role}
     and name like concat('%', #{name}, '%')
     and username like concat('%', #{username}, '%')
     and status = #{status}

order by id desc

mapper.update:
update `sys_user`
username = #{username}, password = #{password}, name = #{name}, role = #{role}, student_no = #{studentNo}, teacher_no = #{teacherNo}, college = #{college}, major = #{major}, class_name = #{className}, status = #{status}, avatar = #{avatar}, create_time = #{createTime}, update_time = #{updateTime},
where id = #{id}
